import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  location?: string;
  currentTemp?: number;
  condition?: string;
  icon?: string;
  humidity?: number;
  windSpeed?: number;
  forecast?: ForecastDay[];
}

const defaultData: Props = {
  location: 'San Francisco, CA',
  currentTemp: 72,
  condition: 'Partly Cloudy',
  icon: '⛅',
  humidity: 45,
  windSpeed: 12,
  forecast: [
    { day: 'Mon', icon: '☀️', high: 75, low: 58 },
    { day: 'Tue', icon: '⛅', high: 72, low: 56 },
    { day: 'Wed', icon: '☁️', high: 68, low: 55 },
    { day: 'Thu', icon: '🌧️', high: 65, low: 52 },
    { day: 'Fri', icon: '☀️', high: 70, low: 54 },
  ]
};

function useComponent(props: Props) {
  const data = useMemo(() => {
    return { ...defaultData, ...props };
  }, [props]);

  return { data };
}

export default function Component(props: Props) {
  const { data } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Card padding={24} shadow="lg" radius="xl">
        <Stack gap={24}>
          <Stack direction="horizontal" justify="between" align="center">
            <Stack gap={4}>
              <Text variant="body" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {data.location}
              </Text>
              <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                {data.currentTemp}°
              </Text>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
                {data.condition}
              </Text>
            </Stack>
            <div style={{ fontSize: '64px', lineHeight: 1 }}>
              {data.icon}
            </div>
          </Stack>

          <Stack direction="horizontal" gap={32}>
            <Stack gap={4}>
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                HUMIDITY
              </Text>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {data.humidity}%
              </Text>
            </Stack>
            <Stack gap={4}>
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                WIND
              </Text>
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {data.windSpeed} mph
              </Text>
            </Stack>
          </Stack>

          <Divider margin={0} />

          <Stack gap={16}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              5-Day Forecast
            </Text>
            <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-lg, 12px)" padding={16}>
              <Stack direction="horizontal" justify="between">
                {data.forecast?.map((day, i) => (
                  <Stack key={i} align="center" gap={8}>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {day.day}
                    </Text>
                    <div style={{ fontSize: '24px', lineHeight: 1 }}>{day.icon}</div>
                    <Stack gap={2} align="center">
                      <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                        {day.high}°
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {day.low}°
                      </Text>
                    </Stack>
                  </Stack>
                ))}
              </Stack>
            </Box>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
