  'alkaline earth metal': { bg: 'var(--ggui-color-warning-100, #fef3c7)', border: 'var(--ggui-color-warning-300, #fcd34d)', text: 'var(--ggui-color-warning-900, #78350f)' },
  'metalloid': { bg: 'var(--ggui-color-success-100, #dcfce7)', border: 'var(--ggui-color-success-300, #86efac)', text: 'var(--ggui-color-success-900, #14532d)' },
  'polyatomic nonmetal': { bg: 'var(--ggui-color-success-50, #f0fdf4)', border: 'var(--ggui-color-success-200, #bbf7d0)', text: 'var(--ggui-color-success-900, #14532d)' },
  'post-transition metal': { bg: 'var(--ggui-color-primary-50, #f0f9ff)', border: 'var(--ggui-color-primary-200, #bae6fd)', text: 'var(--ggui-color-primary-900, #0c4a6e)' },
  'transition metal': { bg: 'var(--ggui-color-warning-50, #fffbeb)', border: 'var(--ggui-color-warning-200, #fde68a)', text: 'var(--ggui-color-warning-900, #78350f)' },
  'lanthanide': { bg: 'var(--ggui-color-info-50, #ecfeff)', border: 'var(--ggui-color-info-200, #a5f3fc)', text: 'var(--ggui-color-info-900, #164e63)' },
  'actinide': { bg: 'var(--ggui-color-error-50, #fef2f2)', border: 'var(--ggui-color-error-200, #fecaca)', text: 'var(--ggui-color-error-900, #7f1d1d)' },
  'unknown': { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', border: 'var(--ggui-color-outline, #d4d4d8)', text: 'var(--ggui-color-onSurface, #18181b)' }
};

const DEFAULT_ELEMENTS: ElementData[] = [
  { atomicNumber: 1, symbol: 'H', name: 'Hydrogen', atomicWeight: 1.008, category: 'diatomic nonmetal', gridRow: 1, gridColumn: 1 },
  { atomicNumber: 2, symbol: 'He', name: 'Helium', atomicWeight: 4.0026, category: 'noble gas', gridRow: 1, gridColumn: 18 },
  { atomicNumber: 3, symbol: 'Li', name: 'Lithium', atomicWeight: 6.94, category: 'alkali metal', gridRow: 2, gridColumn: 1 },
  { atomicNumber: 4, symbol: 'Be', name: 'Beryllium', atomicWeight: 9.0122, category: 'alkaline earth metal', gridRow: 2, gridColumn: 2 },
