function useComponent(props: Props) {
  const { elements = DEFAULT_ELEMENTS } = props;
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<ElementData | null>(null);

  const matchSearch = useCallback((el: ElementData) => {
    if (!search.trim()) return true;
    const term = search.toLowerCase();
    return el.name.toLowerCase().includes(term) || el.symbol.toLowerCase().includes(term);
  }, [search]);

  return { elements, search, setSearch, selected, setSelected, matchSearch };
}

function ElementCell({ el, onClick, dim }: { el: ElementData, onClick: () => void, dim: boolean }) {
  const colors = categoryColors[el.category] || categoryColors.unknown;
  return (
    <button
      onClick={onClick}
      style={{
        gridRow: el.gridRow,
        gridColumn: el.gridColumn,
        aspectRatio: '1 / 1',
        position: 'relative',
        backgroundColor: colors.bg,
        border: `1px solid ${colors.border}`,
        color: colors.text,
        borderRadius: 'var(--ggui-shape-radius-sm)',
        cursor: 'pointer',
        padding: 0,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        opacity: dim ? 0.2 : 1,
        transition: 'opacity 200ms ease, transform 100ms ease',
        boxShadow: 'var(--ggui-shape-shadow-sm)',
        zIndex: 1
      }}
      onMouseEnter={(e) => { e.currentTarget.style.transform = 'scale(1.1)'; e.currentTarget.style.zIndex = '10'; }}
      onMouseLeave={(e) => { e.currentTarget.style.transform = 'scale(1)'; e.currentTarget.style.zIndex = '1'; }}
      aria-label={el.name}
      title={el.name}
    >
      <span style={{ position: 'absolute', top: 2, left: 4, fontSize: '10px', fontWeight: 'var(--ggui-font-weight-medium)' }}>
        {el.atomicNumber}
      </span>
      <span style={{ fontSize: 'var(--ggui-font-size-lg)', fontWeight: 'var(--ggui-font-weight-bold)' }}>
        {el.symbol}
      </span>
    </button>
  );
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-4)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Periodic Table of Elements</Heading>

        <SearchField 
          value={state.search}
          onChange={state.setSearch}
          placeholder="Search by name or symbol..."
        />

        <div style={{ overflowX: 'auto', width: '100%' }}>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(40px, 1fr))',
            gap: 'var(--ggui-spacing-1)',
            minWidth: '800px',
            paddingBottom: 'var(--ggui-spacing-4)'
          }}>
            {state.elements.map(el => (
              <ElementCell 
                 key={el.atomicNumber} 
                 el={el} 
                 onClick={() => state.setSelected(el)}
                 dim={!state.matchSearch(el)}
              />
            ))}
          </div>
        </div>

        {state.selected ? (
          <Card padding={24}>
            <Stack direction="horizontal" gap={24} align="center">
              {(() => {
                const colors = categoryColors[state.selected.category] || categoryColors.unknown;
                return (
                  <div style={{
                    width: 100,
                    height: 100,
                    backgroundColor: colors.bg,
                    border: `2px solid ${colors.border}`,
                    color: colors.text,
                    borderRadius: 'var(--ggui-shape-radius-md)',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    position: 'relative'
                  }}>
                    <span style={{ position: 'absolute', top: 4, left: 8, fontSize: 'var(--ggui-font-size-sm)', fontWeight: 'var(--ggui-font-weight-medium)' }}>
                      {state.selected.atomicNumber}
                    </span>
                    <span style={{ fontSize: 'var(--ggui-font-size-4xl)', fontWeight: 'var(--ggui-font-weight-bold)' }}>
                      {state.selected.symbol}
                    </span>
                  </div>
                );
              })()}

              <Stack gap={8}>
                <Heading level={3}>{state.selected.name}</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  <strong>Atomic Weight:</strong> {state.selected.atomicWeight}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" style={{ textTransform: 'capitalize' }}>
                  <strong>Category:</strong> {state.selected.category}
                </Text>
              </Stack>
            </Stack>
          </Card>
        ) : (
          <Card padding={24}>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" align="center">
              Select an element to view details
            </Text>
          </Card>
        )}

        <Box>
           <Heading level={4}>Legend</Heading>
           <Spacer size={8} />
           <Stack direction="horizontal" wrap gap={16}>
             {Object.entries(categoryColors).map(([cat, colors]) => (
               <div key={cat} style={{ display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)' }}>
                 <div style={{
                   width: 16, height: 16,
                   backgroundColor: colors.bg,
                   border: `1px solid ${colors.border}`,
                   borderRadius: 'var(--ggui-shape-radius-sm, 4px)'
                 }} />
                 <Text variant="caption" style={{ textTransform: 'capitalize' }}>{cat}</Text>
               </div>
             ))}
           </Stack>
        </Box>
      </Stack>
    </Container>
  );
}

