import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  properties: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: 'light' | 'dark';
  };
  actions?: {
    complete?: (data: {
      name: string;
      email: string;
      avatar: string;
      role: string;
      emailNotifications: boolean;
      theme: string;
    }) => void;
  };
}

// Action handlers (call these from event handlers):
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}
function useComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.properties?.name || '');
  const [email, setEmail] = useState(props.properties?.email || '');
  const [avatar, setAvatar] = useState(props.properties?.avatar || '');
  const [role, setRole] = useState(props.properties?.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.properties?.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.properties?.theme || 'light');

  const isValidEmail = (email: string) => /\S+@\S+\.\S+/.test(email);

  const isStep1Valid = name.trim().length > 0 && isValidEmail(email) && avatar.length > 0;
  const isStep2Valid = role.length > 0;

  const handleNext = useCallback(() => {
    if (step === 1 && isStep1Valid) setStep(2);
    else if (step === 2 && isStep2Valid) setStep(3);
  }, [step, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    if (step > 1) setStep(step - 1);
  }, [step]);

  const handleComplete = useCallback(() => {
    if (props.actions?.complete) {
      props.actions.complete({
        name,
        email,
        avatar,
        role,
        emailNotifications,
        theme
      });
    }
  }, [props.actions, name, email, avatar, role, emailNotifications, theme]);

  return {
    step,
    name, setName,
    email, setEmail,
    avatar, setAvatar,
    role, setRole,
    emailNotifications, setEmailNotifications,
    theme, setTheme,
    isStep1Valid,
    isStep2Valid,
    isValidEmail,
    handleNext,
    handleBack,
    handleComplete
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const emailError = state.email.length > 0 && !state.isValidEmail(state.email) ? 'Invalid email format' : undefined;
  const avatars = ['🧑‍💻', '👩‍🎨', '👨‍💼', '🤖'];

  return (
    <Container maxWidth="md" padding={24}>
      <style>{`
        @keyframes wizardFadeIn { 
          from { opacity: 0; transform: translateY(10px); } 
          to { opacity: 1; transform: translateY(0); } 
        }
      `}</style>
      <Card padding={32} shadow="md">
        <Stack gap={24}>
          <Stack gap={8}>
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={3}>Profile Setup</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {state.step} of 3</Text>
            </Stack>
            <Progress value={(state.step / 3) * 100} size="md" />
          </Stack>

          <div style={{ animation: 'wizardFadeIn 300ms ease-out' }} key={state.step}>
            {state.step === 1 && (
              <Stack gap={20}>
                <Heading level={5}>Personal Information</Heading>
                <Input label="Full Name" placeholder="Jane Doe" value={state.name} onChange={state.setName} required />
                <Input label="Email Address" type="email" placeholder="jane@example.com" value={state.email} onChange={state.setEmail} error={emailError} required />
                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Choose an Avatar <Text as="span" color="var(--ggui-color-error-500, #ef4444)">*</Text></Text>
                  <Stack direction="horizontal" gap={12}>
                    {avatars.map(a => (
                      <button
                        key={a}
                        onClick={() => state.setAvatar(a)}
                        type="button"
                        style={{
                          padding: 'var(--ggui-spacing-4, 16px)',
                          borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                          background: state.avatar === a ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                          border: state.avatar === a ? '2px solid var(--ggui-color-primary-500, #0ea5e9)' : '2px solid transparent',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          fontSize: 'var(--ggui-font-size-2xl, 24px)',
                          cursor: 'pointer',
                          outline: 'none',
                          transition: 'all 200ms ease-in-out'
                        }}
                      >
                        {a}
                      </button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {state.step === 2 && (
              <Stack gap={20}>
                <Heading level={5}>Preferences</Heading>
                <Select
                  label="Your Role"
                  value={state.role}
                  onChange={state.setRole}
                  options={[
                    { value: 'Developer', label: 'Developer' },
                    { value: 'Designer', label: 'Designer' },
                    { value: 'Manager', label: 'Manager' },
                    { value: 'Other', label: 'Other' },
                  ]}
                  placeholder="Select a role..."
                  required
                />
                <Divider margin={16} />
                <Toggle
                  label="Receive Email Notifications"
                  checked={state.emailNotifications}
                  onChange={state.setEmailNotifications}
                />
                <Divider margin={16} />
                <RadioGroup
                  label="Theme Preference"
                  value={state.theme}
                  onChange={(val) => state.setTheme(val as 'light' | 'dark')}
                  options={[
                    { value: 'light', label: 'Light Theme' },
                    { value: 'dark', label: 'Dark Theme' },
                  ]}
                />
              </Stack>
            )}

            {state.step === 3 && (
              <Stack gap={20}>
                <Heading level={5}>Review & Confirm</Heading>
                <Box padding={16} borderRadius={8} background="var(--ggui-color-surfaceVariant, #f4f4f5)">
                  <Stack gap={16}>
                    <Stack direction="horizontal" align="center" gap={16}>
                      <Box
                        padding={8}
                        borderRadius="50%"
                        background="var(--ggui-color-surface, #ffffff)"
                        style={{ fontSize: 'var(--ggui-font-size-3xl, 30px)', display: 'flex', alignItems: 'center', justifyContent: 'center', width: '64px', height: '64px', border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}
                      >
                        {state.avatar}
                      </Box>
                      <Stack gap={4}>
                        <Text variant="bodyLarge" weight="bold">{state.name}</Text>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{state.email}</Text>
                      </Stack>
                    </Stack>
                    <Divider margin={8} />
                    <Stack gap={8}>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                        <Text variant="bodySmall" weight="medium">{state.role}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Notifications</Text>
                        <Text variant="bodySmall" weight="medium">{state.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                        <Text variant="bodySmall" weight="medium">{state.theme === 'light' ? 'Light' : 'Dark'}</Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}
          </div>

          <Divider margin={24} />

          <Stack direction="horizontal" justify={state.step > 1 ? 'between' : 'end'} align="center">
            {state.step > 1 && (
              <Button variant="ghost" onClick={state.handleBack}>Go Back</Button>
            )}

            {state.step < 3 ? (
              <Button
                variant="primary"
                onClick={state.handleNext}
                disabled={(state.step === 1 && !state.isStep1Valid) || (state.step === 2 && !state.isStep2Valid)}
              >
                Next Step
              </Button>
            ) : (
              <Button variant="primary" onClick={state.handleComplete}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  currentTemp: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

function useComponent(props: Props) {
  return {
    ...props,
  };
}

export default function Component(props: Props) {
  const { currentTemp, condition, humidity, windSpeed, forecast } = useComponent(props);

  return (
    <Card padding={24} shadow="md">
      <Stack gap={24}>
        <Stack align="center" gap={8}>
          <Heading level={1}>{currentTemp}°</Heading>
          <Text variant="bodyLarge">{condition}</Text>
        </Stack>
        <Row justify="between">
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity: {humidity}%</Text>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind: {windSpeed} mph</Text>
        </Row>
        <Divider />
        <Stack direction="horizontal" justify="between" align="center">
          {forecast.map((f, i) => (
            <Stack key={i} align="center" gap={8}>
              <Text variant="caption" weight="semibold">{f.day}</Text>
              <Text>{f.icon}</Text>
              <Stack gap={2} align="center">
                <Text variant="bodySmall" weight="bold">{f.high}°</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{f.low}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  elements: {
    atomicNumber: number;
    symbol: string;
    name: string;
    atomicWeight: number;
    category: string;
    row: number;
    column: number;
  }[];
}

function useComponent(props: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const filteredElements = useMemo(() => {
    const term = searchTerm.toLowerCase();
    return props.elements.filter(
      (el) => el.name.toLowerCase().includes(term) || el.symbol.toLowerCase().includes(term)
    );
  }, [props.elements, searchTerm]);

  const categories = useMemo(() => Array.from(new Set(props.elements.map(e => e.category))), [props.elements]);

  return { searchTerm, setSearchTerm, selectedElement, setSelectedElement, filteredElements, categories };
}

export default function Component(props: Props) {
  const { searchTerm, setSearchTerm, selectedElement, setSelectedElement, filteredElements, categories } = useComponent(props);

  const getCategoryColor = (cat: string) => {
    const colors: Record<string, string> = {
      'noble-gas': 'var(--ggui-color-info-500)',
      'halogen': 'var(--ggui-color-warning-500)',
      'alkali-metal': 'var(--ggui-color-error-500)',
      'transition-metal': 'var(--ggui-color-primary-500)',
    };
    return colors[cat] || 'var(--ggui-color-outline)';
  };

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={16}>
        <Heading level={1}>Periodic Table</Heading>
        <Input label="Search Elements" placeholder="Search by name or symbol..." value={searchTerm} onChange={setSearchTerm} />

        <Box background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius="md" style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: '4px' }}>
          {filteredElements.map((el) => (
            <div key={el.symbol} onClick={() => setSelectedElement(el)} style={{ gridRow: el.row, gridColumn: el.column, cursor: 'pointer' }}>
              <Card padding={8} style={{ backgroundColor: getCategoryColor(el.category) }}>
                <Text variant="caption">{el.atomicNumber}</Text>
                <Heading level={6}>{el.symbol}</Heading>
              </Card>
            </div>
          ))}
        </Box>

        {selectedElement && (
          <Card padding={24}>
            <Heading level={3}>{selectedElement.name} ({selectedElement.symbol})</Heading>
            <Text>Atomic Number: {selectedElement.atomicNumber}</Text>
            <Text>Weight: {selectedElement.atomicWeight}</Text>
            <Text>Category: {selectedElement.category}</Text>
            <Button variant="ghost" onClick={() => setSelectedElement(null)}>Close</Button>
          </Card>
        )}

        <Stack direction="horizontal" gap={12} wrap>
          {categories.map(cat => (
            <Stack key={cat} direction="horizontal" gap={4} align="center">
              <Box borderRadius="full" style={{ width: 12, height: 12, background: getCategoryColor(cat) }} />
              <Text variant="caption">{cat}</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

interface Props {
  actions?: {
    complete?: (data: any) => void;
  };
}

// Action handlers (call these from event handlers):
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}
function useComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [data, setData] = useState({
    name: '',
    email: '',
    avatar: '🧑‍💻',
    role: 'Developer',
    emailNotifications: true,
    theme: 'dark'
  });

  const isStep1Valid = useMemo(() => data.name.trim() !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email), [data.name, data.email]);

  const updateData = (key: string, value: any) => setData(d => ({ ...d, [key]: value }));
  const next = () => setStep(s => Math.min(s + 1, 3));
  const back = () => setStep(s => Math.max(s - 1, 1));

  const complete = () => {
    if (props.actions && props.actions.complete) {
      props.actions.complete(data);
    }
  };

  return { step, data, updateData, next, back, complete, isStep1Valid };
}

export default function Component(props: Props) {
  const { step, data, updateData, next, back, complete, isStep1Valid } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>Onboarding Wizard</Heading>
        <Progress value={(step / 3) * 100} />
        <Text variant="label">Step {step} of 3</Text>

        {step === 1 && (
          <Stack gap={16}>
            <Input label="Name" value={data.name} onChange={(v) => updateData('name', v)} required />
            <Input label="Email" type="email" value={data.email} onChange={(v) => updateData('email', v)} required />
            <RadioGroup label="Avatar" value={data.avatar} onChange={(v) => updateData('avatar', v)} options={[
              { value: '🧑‍💻', label: '🧑‍💻' }, { value: '🎨', label: '🎨' }, { value: '👔', label: '👔' }, { value: '🚀', label: '🚀' }
            ]} direction="horizontal" />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={16}>
            <Select label="Role" value={data.role} onChange={(v) => updateData('role', v)} options={[
              { value: 'Developer', label: 'Developer' }, { value: 'Designer', label: 'Designer' }, { value: 'Manager', label: 'Manager' }, { value: 'Other', label: 'Other' }
            ]} />
            <Toggle label="Email Notifications" checked={data.emailNotifications} onChange={(v) => updateData('emailNotifications', v)} />
            <Toggle label="Dark Theme" checked={data.theme === 'dark'} onChange={(v) => updateData('theme', v ? 'dark' : 'light')} />
          </Stack>
        )}

        {step === 3 && (
          <Card>
            <Stack gap={8}>
              <Heading level={4}>Review</Heading>
              <Text>Name: {data.name}</Text>
              <Text>Email: {data.email}</Text>
              <Text>Role: {data.role}</Text>
            </Stack>
          </Card>
        )}

        <Row justify="between">
          <Button variant="ghost" onClick={back} disabled={step === 1}>Back</Button>
          {step < 3 ? (
            <Button onClick={next} disabled={step === 1 && !isStep1Valid}>Next</Button>
          ) : (
            <Button variant="primary" onClick={complete}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
